  ('social-worker-moex-01881', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作常需要面對非自願案主，在與其會談時要注意的是：', '["強調社工員對案主的社會控制權力", "告知案主，社工員在保密上的限制", "尊重案主的自我決定權不加以干涉", "不花過多時間給沒有改變意願案主"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01882', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不是團體方案產生的原因？', '["基於案主的需求", "考量社區的需求", "機構的服務使命", "社工員自己的需求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
