  ('social-worker-moex-01884', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列對個案工作訪視的描述，那些是正確的？①是為了瞭解或促進案主適應的相關情況而使用的方法之', '["像是病人因為都在醫院獲得協助，所以不用進行家庭訪視", "社工員進行訪視時，也必須要考量 到自己的人身安全風險", "為了瞭解案主的真實情況，社工員要安排出其不意地訪視  ⑤家庭訪視的焦 點雖是在家庭，也要瞭解其所在的社區環境  ⑥社工員進行訪視時，要選擇類似會談室的場合進行訪視", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01885', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者對於危機調適模式概念和運用的陳述正確？', '["小學轉換國中就讀階段，就可能產生情境性危機（situational crisis）", "和優勢觀點一致，認為案主有能力積極參與處遇", "危機調適可以運用在天災和角色執行困難的議題", "危機是指人無法處理並出現身心狀態失衡的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01886', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列對團體工作的價值與倫理議題說明，何者錯誤？', '["團體工作者應該要保護團體成員在團體中不受傷害", "團體工作者要避免因自身利益剝削成員應有的權益", "團體工作者應該告知成員在團體中履行保密的限制", "團體的決定有風險時，團體工作者都應尊重不介入"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
